```class Solution {
public:
    int numberOfSpecialChars(string word) {
        int res = 0, prev = -1;
        for (int i = 0; i < word.size(); i++) {
            if (islower(word[i])) {
                prev = i;
            } else if (prev != -1) {
                res++;
                prev = -1;
            }
        }
        return res;
    }
};```
